SELECT v.view_id, v.user_id, v.fund_id, f.fund_code, f.fund_name, f.fund_type, f.risk_level, c.company_name, s.total_score, s.recommend_level, pm.return_rate AS return_1y, pm.max_drawdown AS max_drawdown, v.view_time, v.source_page FROM user_recent_fund_view v INNER JOIN fund_info f ON f.fund_id = v.fund_id LEFT JOIN fund_company c ON c.company_id = f.company_id LEFT JOIN s ON s.fund_id = f.fund_id LEFT JOIN pm ON pm.fund_id = f.fund_id
v.user_id = #{userId}
ORDER BY v.view_time DESC, v.view_id DESC
LIMIT #{limit}

